parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "item_name": {
      "type": "string",
      "description": "The name of the item identified in the photo"
    },
    "material_type": {
      "type": "string",
      "description": "The material the item is made of, e.g. PET plastic, aluminium, e-waste"
    },
    "bin_category": {
      "type": "string",
      "description": "Which bin or disposal category it belongs to, e.g. recycling, general waste, e-waste, bulky item"
    },
    "prep_steps": {
      "type": "string",
      "description": "Any preparation needed before disposal, e.g. rinse, remove cap, dry"
    },
    "tip": {
      "type": "string",
      "description": "A short helpful tip for the user about disposing of this item"
    }
  },
  "required": ["item_name", "material_type", "bin_category", "prep_steps", "tip"]
}
